{
  "name": "@node/periodic-table",
  "version": "1.0.0",
  "description": "Interactive periodic table explorer with all 118 elements, category color-coding, search, filtering, and detailed element information",
  "main": "src/index.ts",
  "modnet": {
    "contentType": "science",
    "structure": "collection",
    "mechanics": ["filter", "sort"],
    "boundary": "all",
    "scale": 3
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import { h, Fragment } from 'plaited/template'
import { createSSR } from 'plaited/ssr'
import type { Element, ElementCategory, CategoryInfo } from './types'
import { elements } from './elements-data'

export const categories: CategoryInfo[] = [
  { id: 'alkali-metal', label: 'Alkali Metals', color: '#e65100' },
  { id: 'alkaline-earth', label: 'Alkaline Earth', color: '#f9a825' },
  { id: 'transition-metal', label: 'Transition Metals', color: '#1565c0' },
  { id: 'post-transition-metal', label: 'Post-Transition', color: '#00838f' },
  { id: 'metalloid', label: 'Metalloids', color: '#558b2f' },
  { id: 'nonmetal', label: 'Nonmetals', color: '#2e7d32' },
  { id: 'halogen', label: 'Halogens', color: '#00897b' },
  { id: 'noble-gas', label: 'Noble Gases', color: '#6a1b9a' },
  { id: 'lanthanide', label: 'Lanthanides', color: '#ad1457' },
  { id: 'actinide', label: 'Actinides', color: '#c62828' },
  { id: 'unknown', label: 'Unknown', color: '#616161' },
]

const getCategoryColor = (category: ElementCategory): string => {
  const info = categories.find((c) => c.id === category)
  return info?.color ?? '#616161'
}

const getCategoryBg = (category: ElementCategory): string => {
  const colorMap: Record<ElementCategory, string> = {
    'alkali-metal': '#fff3e0',
    'alkaline-earth': '#fffde7',
    'transition-metal': '#e3f2fd',
    'post-transition-metal': '#e0f7fa',
    'metalloid': '#f1f8e9',
    'nonmetal': '#e8f5e9',
    'halogen': '#e0f2f1',
    'noble-gas': '#f3e5f5',
    'lanthanide': '#fce4ec',
    'actinide': '#ffebee',
    'unknown': '#f5f5f5',
  }
  return colorMap[category]
}

const renderElementCell = (el: Element) => {
  const borderColor = getCategoryColor(el.category)
  const bgColor = getCategoryBg(el.category)

  return h(
    'div',
    {
      class: `element-cell cat-${el.category}`,
      'data-atomic-number': String(el.atomicNumber),
      'data-symbol': el.symbol.toLowerCase(),
      'data-name': el.name.toLowerCase(),
      'data-category': el.category,
      style: `grid-row:${el.row};grid-column:${el.col};background:${bgColor};border:2px solid ${borderColor};`,
      'p-trigger': 'click:selectElement',
    },
    h('span', { class: 'atomic-number' }, String(el.atomicNumber)),
    h('span', { class: 'symbol' }, el.symbol),
    h('span', { class: 'el-name' }, el.name),
    h('span', { class: 'mass' }, String(el.atomicMass))
  )
}

const renderLanthanideLabel = () =>
  h(
    'div',
    {
      class: 'series-label',
      style: 'grid-row:6;grid-column:3;background:#fce4ec;border:2px solid #ad1457;',
    },
    h('span', { class: 'symbol' }, '57-71'),
    h('span', { class: 'el-name' }, 'La-Lu')
  )

const renderActinideLabel = () =>
  h(
    'div',
    {
      class: 'series-label',
      style: 'grid-row:7;grid-column:3;background:#ffebee;border:2px solid #c62828;',
    },
    h('span', { class: 'symbol' }, '89-103'),
    h('span', { class: 'el-name' }, 'Ac-Lr')
  )

const renderCategoryLegend = () =>
  h(
    'div',
    { class: 'category-legend' },
    ...categories.map((cat) =>
      h(
        'button',
        {
          class: 'legend-btn',
          'data-filter-category': cat.id,
          style: `border-left:4px solid ${cat.color};`,
          'p-trigger': 'click:filterCategory',
        },
        cat.label
      )
    ),
    h(
      'button',
      {
        class: 'legend-btn legend-btn-all active',
        'data-filter-category': 'all',
        'p-trigger': 'click:filterCategory',
      },
      'Show All'
    )
  )

const renderSearchBar = () =>
  h(
    'div',
    { class: 'search-container' },
    h('input', {
      type: 'text',
      id: 'search-input',
      class: 'search-input',
      placeholder: 'Search by name, symbol, or atomic number...',
      autocomplete: 'off',
      'p-trigger': 'input:searchElements',
    }),
    h('span', { class: 'search-icon' }, '\u{1F50D}')
  )

const renderDetailPanel = () =>
  h(
    'div',
    { id: 'detail-panel', class: 'detail-panel', style: 'display:none;' },
    h(
      'button',
      { class: 'close-btn', id: 'close-detail', 'p-trigger': 'click:closeDetail' },
      '\u00D7'
    ),
    h('div', { id: 'detail-content', class: 'detail-content' })
  )

const renderStyles = () =>
  h(
    'style',
    {},
    `
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; background: #0f1923; color: #e0e0e0; min-height: 100vh; }
    .periodic-table-explorer { max-width: 1400px; margin: 0 auto; padding: 16px; }
    h1 { text-align: center; font-size: 1.8rem; margin-bottom: 16px; color: #fff; font-weight: 300; letter-spacing: 2px; }
    .controls { display: flex; flex-wrap: wrap; gap: 12px; margin-bottom: 20px; align-items: flex-start; }
    .search-container { position: relative; flex: 1; min-width: 250px; }
    .search-input { width: 100%; padding: 10px 40px 10px 14px; border: 1px solid #37474f; border-radius: 8px; font-size: 14px; background: #1a2733; color: #e0e0e0; outline: none; transition: border-color 0.2s; }
    .search-input:focus { border-color: #42a5f5; }
    .search-input::placeholder { color: #78909c; }
    .search-icon { position: absolute; right: 12px; top: 50%; transform: translateY(-50%); font-size: 16px; opacity: 0.5; }
    .category-legend { display: flex; flex-wrap: wrap; gap: 4px; }
    .legend-btn { padding: 5px 10px; border: 1px solid #37474f; border-radius: 4px; background: #1a2733; color: #b0bec5; cursor: pointer; font-size: 11px; transition: all 0.2s; white-space: nowrap; }
    .legend-btn:hover, .legend-btn.active { background: #263238; color: #fff; border-color: #546e7a; }
    .legend-btn-all { border-left: 4px solid #42a5f5 !important; }
    .table-container { overflow-x: auto; padding-bottom: 8px; }
    .periodic-grid { display: grid; grid-template-columns: repeat(18, minmax(64px, 1fr)); grid-template-rows: repeat(10, auto); gap: 2px; margin-bottom: 8px; min-width: 1150px; }
    .element-cell { padding: 4px; border-radius: 4px; cursor: pointer; display: flex; flex-direction: column; align-items: center; justify-content: center; min-height: 64px; transition: all 0.15s; position: relative; }
    .element-cell:hover { transform: scale(1.15); z-index: 10; box-shadow: 0 4px 20px rgba(0,0,0,0.5); }
    .element-cell.dimmed { opacity: 0.15; }
    .element-cell.highlighted { transform: scale(1.08); box-shadow: 0 2px 12px rgba(0,0,0,0.4); }
    .element-cell .atomic-number { font-size: 9px; opacity: 0.8; align-self: flex-start; position: absolute; top: 3px; left: 5px; }
    .element-cell .symbol { font-size: 18px; font-weight: 700; line-height: 1.2; margin-top: 4px; }
    .element-cell .el-name { font-size: 7px; text-overflow: ellipsis; overflow: hidden; white-space: nowrap; max-width: 100%; opacity: 0.9; }
    .element-cell .mass { font-size: 7px; opacity: 0.6; }
    .element-cell .atomic-number, .element-cell .symbol, .element-cell .el-name, .element-cell .mass { color: #1a1a2e; }
    .series-label { padding: 4px; border-radius: 4px; display: flex; flex-direction: column; align-items: center; justify-content: center; min-height: 64px; cursor: default; }
    .series-label .symbol { font-size: 12px; font-weight: 600; color: #1a1a2e; }
    .series-label .el-name { font-size: 8px; color: #1a1a2e; opacity: 0.7; }
    .spacer-row { grid-column: 1 / -1; height: 12px; }
    .spacer-row-el { grid-row: 8; grid-column: 1; height: 12px; }
    .detail-panel { position: fixed; top: 0; right: 0; width: 380px; height: 100vh; background: #1a2733; border-left: 1px solid #37474f; box-shadow: -4px 0 20px rgba(0,0,0,0.5); z-index: 100; overflow-y: auto; padding: 24px; animation: slideIn 0.2s ease; }
    @keyframes slideIn { from { transform: translateX(100%); } to { transform: translateX(0); } }
    .close-btn { position: absolute; top: 12px; right: 16px; background: none; border: none; color: #78909c; font-size: 28px; cursor: pointer; line-height: 1; padding: 4px; }
    .close-btn:hover { color: #fff; }
    .detail-content { margin-top: 8px; }
    .detail-header { display: flex; align-items: center; gap: 16px; margin-bottom: 20px; padding-bottom: 16px; border-bottom: 1px solid #37474f; }
    .detail-symbol { font-size: 48px; font-weight: 700; width: 80px; height: 80px; display: flex; align-items: center; justify-content: center; border-radius: 12px; }
    .detail-info h2 { font-size: 22px; font-weight: 600; color: #fff; }
    .detail-info .detail-number { font-size: 14px; color: #78909c; }
    .detail-info .detail-mass { font-size: 13px; color: #90a4ae; }
    .detail-info .detail-category { font-size: 11px; padding: 2px 8px; border-radius: 12px; display: inline-block; margin-top: 4px; }
    .detail-section { margin-bottom: 16px; }
    .detail-section h3 { font-size: 11px; text-transform: uppercase; letter-spacing: 1px; color: #546e7a; margin-bottom: 8px; }
    .detail-row { display: flex; justify-content: space-between; padding: 6px 0; border-bottom: 1px solid #263238; font-size: 13px; }
    .detail-row .label { color: #78909c; }
    .detail-row .value { color: #e0e0e0; font-weight: 500; }
    .detail-description { font-size: 13px; line-height: 1.5; color: #b0bec5; background: #0f1923; padding: 12px; border-radius: 8px; margin-top: 8px; }
    .overlay { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.4); z-index: 99; }
    @media (max-width: 768px) {
      .periodic-grid { grid-template-columns: repeat(18, 48px); font-size: 10px; }
      .element-cell { min-height: 48px; padding: 2px; }
      .element-cell .symbol { font-size: 14px; }
      .element-cell .el-name { display: none; }
      .detail-panel { width: 100%; }
    }
    `
  )

const renderScript = () =>
  h(
    'script',
    {},
    `
    const elementsData = ${JSON.stringify(elements)};
    const categoryColors = ${JSON.stringify(Object.fromEntries(categories.map((c) => [c.id, c.color])))};
    const categoryBgs = ${JSON.stringify(Object.fromEntries(categories.map((c) => [c.id, getCategoryBg(c.id)])))};

    const cells = document.querySelectorAll('.element-cell');
    const searchInput = document.getElementById('search-input');
    const detailPanel = document.getElementById('detail-panel');
    const detailContent = document.getElementById('detail-content');
    const closeBtn = document.getElementById('close-detail');
    const filterBtns = document.querySelectorAll('.legend-btn');

    let activeCategory = 'all';
    let searchTerm = '';

    const applyFilters = () => {
      cells.forEach(cell => {
        const cat = cell.dataset.category;
        const name = cell.dataset.name;
        const symbol = cell.dataset.symbol;
        const num = cell.dataset.atomicNumber;
        const matchesCategory = activeCategory === 'all' || cat === activeCategory;
        const matchesSearch = !searchTerm ||
          name.includes(searchTerm) ||
          symbol.includes(searchTerm) ||
          num === searchTerm;
        if (matchesCategory && matchesSearch) {
          cell.classList.remove('dimmed');
          cell.classList.add('highlighted');
        } else if (!searchTerm && activeCategory === 'all') {
          cell.classList.remove('dimmed', 'highlighted');
        } else {
          cell.classList.add('dimmed');
          cell.classList.remove('highlighted');
        }
      });
    };

    searchInput.addEventListener('input', (e) => {
      searchTerm = e.target.value.toLowerCase().trim();
      applyFilters();
    });

    filterBtns.forEach(btn => {
      btn.addEventListener('click', () => {
        filterBtns.forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        activeCategory = btn.dataset.filterCategory;
        applyFilters();
      });
    });

    const formatTemp = (val) => val !== null ? val + ' \\u00B0C' : 'Unknown';

    const showDetail = (atomicNumber) => {
      const el = elementsData.find(e => e.atomicNumber === atomicNumber);
      if (!el) return;
      const color = categoryColors[el.category] || '#616161';
      const bg = categoryBgs[el.category] || '#f5f5f5';
      const catLabel = el.category.split('-').map(w => w[0].toUpperCase() + w.slice(1)).join(' ');

      detailContent.innerHTML = \`
        <div class="detail-header">
          <div class="detail-symbol" style="background:\${bg};color:\${color};border:2px solid \${color};">\${el.symbol}</div>
          <div class="detail-info">
            <h2>\${el.name}</h2>
            <div class="detail-number">Atomic Number \${el.atomicNumber}</div>
            <div class="detail-mass">\${el.atomicMass} u</div>
            <span class="detail-category" style="background:\${color};color:#fff;">\${catLabel}</span>
          </div>
        </div>
        <div class="detail-section">
          <h3>Electron Configuration</h3>
          <div class="detail-row"><span class="value">\${el.electronConfiguration}</span></div>
        </div>
        <div class="detail-section">
          <h3>Properties</h3>
          <div class="detail-row"><span class="label">Oxidation States</span><span class="value">\${el.oxidationStates.map(s => s > 0 ? '+' + s : String(s)).join(', ')}</span></div>
          <div class="detail-row"><span class="label">Melting Point</span><span class="value">\${formatTemp(el.meltingPoint)}</span></div>
          <div class="detail-row"><span class="label">Boiling Point</span><span class="value">\${formatTemp(el.boilingPoint)}</span></div>
          <div class="detail-row"><span class="label">Discovery</span><span class="value">\${el.discoveryYear ? el.discoveryYear : 'Ancient'}</span></div>
        </div>
        <div class="detail-section">
          <h3>About</h3>
          <div class="detail-description">\${el.description}</div>
        </div>
      \`;
      detailPanel.style.display = 'block';
      if (!document.getElementById('detail-overlay')) {
        const overlay = document.createElement('div');
        overlay.id = 'detail-overlay';
        overlay.className = 'overlay';
        overlay.addEventListener('click', closeDetail);
        document.body.appendChild(overlay);
      }
    };

    const closeDetail = () => {
      detailPanel.style.display = 'none';
      const overlay = document.getElementById('detail-overlay');
      if (overlay) overlay.remove();
    };

    cells.forEach(cell => {
      cell.addEventListener('click', () => {
        showDetail(parseInt(cell.dataset.atomicNumber));
      });
    });

    closeBtn.addEventListener('click', closeDetail);

    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') closeDetail();
    });
    `
  )

export const renderPeriodicTable = (): string => {
  const spacer = h('div', { class: 'spacer-row-el', style: 'grid-row:8;grid-column:1/-1;' })

  const template = h(
    Fragment,
    {},
    h(
      'html',
      { lang: 'en' },
      h(
        'head',
        {},
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', {}, 'Periodic Table Explorer'),
        renderStyles()
      ),
      h(
        'body',
        {},
        h(
          'div',
          { class: 'periodic-table-explorer' },
          h('h1', {}, 'Periodic Table of Elements'),
          h(
            'div',
            { class: 'controls' },
            renderSearchBar(),
            renderCategoryLegend()
          ),
          h(
            'div',
            { class: 'table-container' },
            h(
              'div',
              { class: 'periodic-grid' },
              ...elements.map(renderElementCell),
              renderLanthanideLabel(),
              renderActinideLabel(),
              spacer
            )
          ),
          renderDetailPanel()
        ),
        renderScript()
      )
    )
  )

  return '<!DOCTYPE html>' + createSSR(template)
}

import { renderPeriodicTable } from './render'

export { renderPeriodicTable }
export { elements } from './elements-data'
export type { Element, ElementCategory, CategoryInfo } from './types'

const serve = () => {
  const html = renderPeriodicTable()

  return Bun.serve({
    port: 3000,
    fetch: (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '/index.html') {
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      return new Response('Not Found', { status: 404 })
    },
  })
}

if (import.meta.main) {
  const server = serve()
  console.log(`Periodic Table Explorer running at http://localhost:${server.port}`)
}
